  // Transfer metadata from the switch to the new conditional branch.
  if (MDNode *UnpredictableMD =
          SI->getMetadata(LLVMContext::MD_unpredictable))
    Br->setMetadata(LLVMContext::MD_unpredictable, UnpredictableMD);

  if (MDNode *ProfMD = SI->getMetadata(LLVMContext::MD_prof)) {
    SmallVector<uint64_t, 4> Weights;
    extractFromBranchWeightMD64(ProfMD, Weights);
    // Weights: [default, case_0, case_1, ...]
    // Map cases to TrueDest/FalseDest and sum weights.
    uint64_t TrueWeight = 0, FalseWeight = 0;
    if (SI->getDefaultDest() == TrueDest)
      TrueWeight += Weights[0];
    else
      FalseWeight += Weights[0];
    for (auto &Case : SI->cases()) {
      uint64_t W = Weights[Case.getCaseIndex() + 1];
      if (Case.getCaseSuccessor() == TrueDest)
        TrueWeight += W;
      else
        FalseWeight += W;
    }
    SmallVector<uint32_t, 2> NewWeights;
    NewWeights.push_back(TrueWeight);
    NewWeights.push_back(FalseWeight);
    Br->setMetadata(
        LLVMContext::MD_prof,
        MDBuilder(SI->getContext()).createBranchWeights(NewWeights));
  }
